import{_ as a,o,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"56. Public Holidays","description":"","frontmatter":{"title":"56. Public Holidays","eba":"Nurses and Midwives 2024-2028","topics":["hours","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/56-public-holidays.md","filePath":"ebas/nurses-midwives/leave/56-public-holidays.md"}'),i={name:"ebas/nurses-midwives/leave/56-public-holidays.md"};function s(n,e,l,p,d,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_56-public-holidays" tabindex="-1">56. Public Holidays <a class="header-anchor" href="#_56-public-holidays" aria-label="Permalink to &quot;56. Public Holidays&quot;">​</a></h1><p>For the purpose of this clause only, a Weekend Worker is an Employee who works ordinary hours on a Saturday or Sunday.</p><p><strong>56.1</strong> An Employee will be entitled to paid time off (or penalty payments for time worked) in respect of public holidays in accordance with this clause.</p><p><strong>56.2</strong> Subject to clause 56.4, the public holidays to which this clause applies are the days determined under Victorian law as public holidays in respect of the following occasions:</p><p><strong>(a)</strong> New Year&#39;s Day, Australia Day, Christmas Day and Boxing Day; and</p><p><strong>(b)</strong> Good Friday, the Saturday immediately before Easter Sunday (Easter Saturday), Easter Sunday, Easter Monday, Anzac Day, King&#39;s Birthday and Labour Day; and</p><p><strong>(c)</strong> Melbourne Cup Day, or in lieu of Melbourne Cup Day, some other day as determined under Victorian law for a particular locality;</p><p><strong>(d)</strong> the Friday before the AFL Grand Final;</p><p><strong>(e)</strong> any additional public holiday declared or prescribed in Victoria or a locality in respect of occasions other than those set out in subclause 56.2(a); and</p><p><strong>(f)</strong> If a day or days are not determined in respect of any of the occasions in subclause 56.2(a), (b) or (c) under Victorian law in any year, the public holiday for that occasion will be the day or date upon which the public holiday was observed in the previous year.</p><p><strong>56.3</strong> Applicability of penalty payments for some public holidays falling on a weekend</p><p>When Christmas Day, Australia Day, Boxing Day, or New Year&#39;s Day (Actual Day) is a Saturday or a Sunday, and a substitute or additional holiday is determined under Victorian law on another day in respect of any of those occasions (Other Day):</p><p><strong>(a)</strong> Weekend Workers and casual Employees will receive penalty payments pursuant to clause 56.5 for time worked on the Actual Day or on the Other Day (as defined) if the Employee does not work ordinary hours on the Actual Day; and</p><p><strong>(a)</strong> all other Employees will receive penalty payments pursuant to clause 56.5 for time worked on the Other Day (as defined).</p><p><strong>56.4</strong> Substitution of one public holiday for another</p><p><strong>(a)</strong> An Employer and Employee may agree to substitute another day for a day that would otherwise be a public holiday under the Act or this Agreement.</p><p><strong>(b)</strong> An Employer and Employee may agree to substitute another part-day for a part- day that would otherwise be a part-day public holiday under the Act or this Agreement.</p><p><strong>(c)</strong> Where an agreement under subclause (a) or (b) is reached, it will be recorded in writing and a copy given to the Employee.</p><p><strong>56.5</strong> Penalty Payments in respect of public holidays</p><p><strong>(a)</strong> An Employee, other than a casual Employee, who performs work (including overtime work) on a public holiday (or where Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day fall on a weekend, the day to which penalty rates apply pursuant to clause 56.3) will be entitled to be paid;</p><p><strong>(i)</strong> 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>) for the time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> for the time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in <a href="/eba/ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.html">clause 48</a> (Special Rates for Saturday and Sunday)).</p><p><strong>(b)</strong> A casual Employee who performs work (including overtime work) on a public holiday (or where Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day fall on a weekend, the day to which penalty rates apply pursuant to clause 56.3) will be entitled to be paid inclusive of the casual loading;</p><p><strong>(i)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>) for time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 312.5% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>) for time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in <a href="/eba/ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.html">clause 48</a> (Special Rates for Saturday and Sunday)).</p><p><strong>56.6</strong> Public holidays and night duty</p><p><strong>(a)</strong> Definition of part of a shift</p><p>For the purposes of this clause &quot;part of a shift&quot; means that period on a public holiday from:</p><p><strong>(i)</strong> midnight to completion of shift; or</p><p><strong>(ii)</strong> commencement of shift to midnight.</p><p><strong>(b)</strong> A night duty Employee is entitled to be paid:</p><p><strong>(i)</strong> the appropriate public holiday rates for each hour worked on that part of a shift that falls on the public holiday; and</p><p><strong>(ii)</strong> at the pro rata public holiday rostered off benefit for that part of a shift that falls on the public holiday that they are not rostered to work and do not work.</p><p>Example: An Employee whose average hours are 0.6EFT is rostered to work from 9.30pm to 7.30am with the shift commencing the day before the public holiday. The hours worked between midnight and 7.30am fall on the public holiday and each hour attracts the public holiday rate, e.g. 7.6 hours at double time. The same Employee is not rostered to the night shift that commences on the public holiday, i.e. the shift that commences at 9pm. The period from 9.30pm to midnight attracts a pro rata payment 2.5 hours x 0.6 (EFT) hours payable.</p><p><strong>56.7</strong> Accrued days off on public holidays</p><p>See also clause 0 (Accrued Days Off).</p><p>Where a public holiday or part-day public holiday falls on a day upon which a full-time Employee would ordinarily have been required to be on duty, but the Employee is on an accrued day off, another day or part day will be determined by the Employer to be taken by the Employee in lieu of the public holiday or part-day public holiday, such day to be within the same work cycle where practical.</p><p><strong>56.8</strong> Public Holiday not required to work</p><p>Where a public holiday occurs on a day that a part-time or full-time Employee would normally work, but the Employee is not required by the Employer to work on that day, the Employee will be paid an amount equal to the Employee&#39;s ordinary rate of pay for the hours the Employee would normally have worked on that day.</p><p><strong>56.9</strong> Public holidays occurring on rostered days off</p><p><strong>(a)</strong> Subject to subclauses 56.9(c) and (d), a full-time Employee will receive a sum equal to a day&#39;s ordinary pay for public holidays that occur on their rostered day off.</p><p><strong>(b)</strong> Subject to subclauses 56.9(c) and (d), if a public holiday is a part-day public holiday then subclause 56.9(a) will apply on a pro rata basis for the number of ordinary hours on the part-day public holiday.</p><p><strong>(c)</strong> Subject to subclause 56.9(d), if a public holiday falls on Saturday or Sunday then subclause 56.9(a) will only apply to Weekend Workers.</p><p><strong>(d)</strong> Where on each occasion an Other Day (as defined) applies as a public holiday in respect of that occasion, and:</p><p><strong>(i)</strong> the Employee is rostered off for both the Actual Day and the Other Day (as defined), then only one day&#39;s payment will be made under subclause 56.9(a); or</p><p><strong>(ii)</strong> the Employee works only on one of either the Actual Day or the Other Day (as defined), and receives penalty rates for the day worked, the Employee will not receive a payment under subclause 56.9(a) in respect of the day not worked.</p><p><strong>56.10</strong> Additional entitlement for part-time Employees rostered off duty</p><p>NOTE: This clause operates in addition to clause 56.8 for part-time employees.</p><p>The entitlement to public holiday benefits for a part-time Employee who is rostered off duty on the day on which a public holiday occurs is to be determined as follows:</p><p><strong>(a)</strong> Where on each occasion that Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day falls on an Other Day (as defined), and the Other Day applies as a public holiday in respect of that occasion, and:</p><p><strong>(i)</strong> a part-time Employee is not rostered on for both the Actual Day and the Other Day (as defined), then only one day&#39;s payment will be made under this clause; or</p><p><strong>(ii)</strong> a part-time Employee works on either the Actual Day or the Other Day (as defined), and receives penalty rates for the day worked, the part-time Employee will not receive a payment in respect of the day not worked.</p><p><strong>(b)</strong> Where a public holiday occurs on a day a part-time Employee is not rostered to work, the part-time Employee will receive a payment in respect of that public holiday equal to their ordinary pay for the average daily hours worked by that</p><p>Employee over the previous six months, or their period of employment by the Employer if less than six months.</p><p>Example:</p><p>Average Hours Shift Length Base Payment Penalty Payment</p><p>24 hours X 8 hours 5.05 hours T1 5.05 hrs</p><p>38 hours</p><p><strong>(c)</strong> A part-time Employee who is only ever employed between Monday to Friday, will not receive any entitlement for a public holiday falling on a Saturday or Sunday. If an additional day or substitute day is declared on a weekday in respect to the relevant Saturday or Sunday, this exclusion will not affect the benefits applicable to the additional day or substitute day.</p><p><strong>56.11</strong> Recall on a public holiday</p><p>A benefit arising from clause 56.8, 56.9, or 56.10 will not be diminished where an Employee is required to, and does, perform recall work on that day in accordance with subclause 49.2(a)(v).</p><p><strong>56.12</strong> Annual leave on a public holiday</p><p>See <a href="/eba/ebas/nurses-midwives/leave/57-annual-leave.html">clause 57</a> (Annual Leave).</p><p><strong>56.13</strong> Personal leave on a public holiday</p><p>See <a href="/eba/ebas/nurses-midwives/leave/61-personal-leave.html">clause 61</a> (Personal Leave).</p><p>Plain language terms: public holiday pay, holiday pay, PH pay, penalty rates holidays.</p>',66)])])}const c=a(i,[["render",s]]);export{u as __pageData,c as default};
